import React, { useState, useEffect } from 'react';
import AppearanceDetail from './AppearanceDetail';

function AppearanceList() {
  const [appearances, setAppearances] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedPlayer, setSelectedPlayer] = useState(null);

  useEffect(() => {
    fetchAppearances();
  }, []);

  const fetchAppearances = async () => {
    try {
      const response = await fetch('https://api.jsonbin.io/v3/b/69b3095eaa77b81da9dca08d');
      const data = await response.json();
      if (data && data.record && Array.isArray(data.record)) {
        const cleanedAppearances = data.record.map(player => ({
          ...player,
          forename: String(player.forename || '').trim(),
          surname: String(player.surname || '').trim(),
          totalAppearances: Number(player.totalAppearances) || 0,
          totalStarts: Number(player.totalStarts) || 0,
          totalSubstitutes: Number(player.totalSubstitutes) || 0,
          starterPercentage: Number(player.starterPercentage) || 0
        })).sort((a, b) => b.totalAppearances - a.totalAppearances);
        setAppearances(cleanedAppearances);
      } else {
        setError('Data format issue');
      }
      setLoading(false);
    } catch (error) {
      console.error('Fetch error:', error);
      setError(error.message);
      setLoading(false);
    }
  };

  // Show detail view if a player is selected
  if (selectedPlayer) {
    return (
      <AppearanceDetail 
        player={selectedPlayer} 
        onBack={() => setSelectedPlayer(null)} 
      />
    );
  }

  if (loading) return <div style={{ padding: '20px' }}>Loading appearances...</div>;
  if (error) return <div style={{ padding: '20px' }}>Error: {error}</div>;

  return (
    <div style={{ padding: '20px' }}>
      <div style={{ display: 'flex', alignItems: 'center', marginBottom: '20px' }}>
        <img 
          src="/bwfc.png" 
          alt="BWFC" 
          style={{ width: '50px', height: '50px', marginRight: '15px' }}
          onError={(e) => { e.target.style.display = 'none'; }}
        />
        <h1 style={{ color: '#003f7f', margin: 0 }}>Player Appearances</h1>
      </div>

      <div style={{ maxWidth: '600px' }}>
        {appearances.map((player, index) => (
          <div 
            key={`${player.forename}-${player.surname}`} 
            onClick={() => setSelectedPlayer(player)}
            style={{
              backgroundColor: '#003f7f',
              color: 'white',
              padding: '15px',
              marginBottom: '8px',
              borderRadius: '8px',
              cursor: 'pointer',
              transition: 'transform 0.2s ease',
            }}
            onMouseOver={(e) => e.target.style.transform = 'translateX(5px)'}
            onMouseOut={(e) => e.target.style.transform = 'translateX(0)'}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div style={{ display: 'flex', alignItems: 'center', flex: 1 }}>
                <div style={{
                  backgroundColor: '#ffffff',
                  color: '#003f7f',
                  width: '30px',
                  height: '30px',
                  borderRadius: '50%',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontWeight: 'bold',
                  marginRight: '15px'
                }}>
                  {index + 1}
                </div>
                <div>
                  <div style={{ fontWeight: 'bold', fontSize: '18px' }}>
                    {player.forename} {player.surname}
                  </div>
                  <div style={{ fontSize: '14px', opacity: 0.9 }}>
                    {player.totalStarts} starts, {player.totalSubstitutes} sub appearances
                  </div>
                </div>
              </div>
              <div style={{ textAlign: 'right' }}>
                <div style={{ 
                  fontSize: '24px', 
                  fontWeight: 'bold',
                  minWidth: '60px'
                }}>
                  {player.totalAppearances}
                </div>
                <div style={{ fontSize: '12px', opacity: 0.8 }}>
                  {player.starterPercentage}% starter
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default AppearanceList;
